import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = (p.get('requestedVersion',''), p.get('resolvedVersion',''))
        result[name] = pkgs
    return result

base = extract(b)
after = extract(a)
print('=== BASELINE ===')
for proj, pkgs in sorted(base.items()):
    for pid, (req,res) in sorted(pkgs.items()):
        print(f'{proj}: {pid} requested={req} resolved={res}')
print()
print('=== AFTER CPM ===')
for proj, pkgs in sorted(after.items()):
    for pid, (req,res) in sorted(pkgs.items()):
        print(f'{proj}: {pid} requested={req} resolved={res}')
print()
print('=== CHANGES ===')
for proj in sorted(set(list(base.keys()) + list(after.keys()))):
    bp = base.get(proj, {})
    ap = after.get(proj, {})
    for pid in sorted(set(list(bp.keys()) + list(ap.keys()))):
        bv = bp.get(pid, (None, None))
        av = ap.get(pid, (None, None))
        if bv != av:
            print(f'{proj}: {pid} {bv} -> {av}')
"

